/**
 * Tests for logger
 */

import { createLogger } from '../src/utils/logger.js';
import fs from 'fs';
import path from 'path';

describe('Logger', () => {
  const logsDir = path.join(process.cwd(), 'logs');

  beforeAll(() => {
    // Ensure logs directory exists
    if (!fs.existsSync(logsDir)) {
      fs.mkdirSync(logsDir, { recursive: true });
    }
  });

  afterEach(() => {
    // Clean up log files after each test
    const logFiles = ['error.log', 'combined.log', 'debug.log'];
    logFiles.forEach(file => {
      const filePath = path.join(logsDir, file);
      if (fs.existsSync(filePath)) {
        try {
          fs.unlinkSync(filePath);
        } catch (err) {
          // Ignore errors during cleanup
        }
      }
    });
  });

  describe('createLogger', () => {
    it('should create logger with default options', () => {
      const logger = createLogger({ silent: true });
      
      expect(logger).toBeDefined();
      expect(logger.level).toBe('info');
    });

    it('should create logger with custom level', () => {
      const logger = createLogger({ level: 'warn', silent: true });
      
      expect(logger.level).toBe('warn');
    });

    it('should create logger with debug mode', () => {
      const logger = createLogger({ debugMode: true, silent: true });
      
      expect(logger.level).toBe('debug');
    });

    it('should have required transports', () => {
      const logger = createLogger({ silent: true });
      
      // Should have at least file transports
      expect(logger.transports.length).toBeGreaterThanOrEqual(2);
    });
  });

  describe('logging methods', () => {
    it('should log error messages', () => {
      const logger = createLogger({ silent: true });
      
      expect(() => {
        logger.error('Test error message');
      }).not.toThrow();
    });

    it('should log warn messages', () => {
      const logger = createLogger({ silent: true });
      
      expect(() => {
        logger.warn('Test warning message');
      }).not.toThrow();
    });

    it('should log info messages', () => {
      const logger = createLogger({ silent: true });
      
      expect(() => {
        logger.info('Test info message');
      }).not.toThrow();
    });

    it('should log debug messages in debug mode', () => {
      const logger = createLogger({ debugMode: true, silent: true });
      
      expect(() => {
        logger.debug('Test debug message');
      }).not.toThrow();
    });

    it('should log with metadata', () => {
      const logger = createLogger({ silent: true });
      
      expect(() => {
        logger.info('Test message', { userId: 123, action: 'test' });
      }).not.toThrow();
    });
  });

  describe('helper methods', () => {
    it('should have setDebugMode method', () => {
      const logger = createLogger({ silent: true });
      
      expect(logger.setDebugMode).toBeDefined();
      expect(typeof logger.setDebugMode).toBe('function');
    });

    it('should have getLogLevel method', () => {
      const logger = createLogger({ silent: true });
      
      expect(logger.getLogLevel).toBeDefined();
      expect(typeof logger.getLogLevel).toBe('function');
      expect(logger.getLogLevel()).toBe('info');
    });

    it('should have isDebugMode method', () => {
      const logger = createLogger({ silent: true });
      
      expect(logger.isDebugMode).toBeDefined();
      expect(typeof logger.isDebugMode).toBe('function');
      expect(logger.isDebugMode()).toBe(false);
    });

    it('should enable debug mode', () => {
      const logger = createLogger({ silent: true });
      
      logger.setDebugMode(true);
      
      expect(logger.isDebugMode()).toBe(true);
    });

    it('should disable debug mode', () => {
      const logger = createLogger({ debugMode: true, silent: true });
      
      expect(logger.isDebugMode()).toBe(true);
      
      logger.setDebugMode(false);
      
      expect(logger.isDebugMode()).toBe(false);
    });
  });

  describe('log levels', () => {
    it('should respect log level hierarchy', () => {
      const logger = createLogger({ level: 'warn', silent: true });
      
      // Warn level should not log info or debug
      expect(logger.level).toBe('warn');
    });

    it('should log all levels in debug mode', () => {
      const logger = createLogger({ debugMode: true, silent: true });
      
      expect(logger.level).toBe('debug');
    });
  });

  describe('file transports', () => {
    it('should create error log file', (done) => {
      const logger = createLogger({ silent: true });
      
      logger.error('Test error for file');
      
      // Give winston time to write to file
      setTimeout(() => {
        const errorLogPath = path.join(logsDir, 'error.log');
        const exists = fs.existsSync(errorLogPath);
        
        expect(exists).toBe(true);
        done();
      }, 100);
    });

    it('should create combined log file', (done) => {
      const logger = createLogger({ silent: true });
      
      logger.info('Test info for file');
      
      // Give winston time to write to file
      setTimeout(() => {
        const combinedLogPath = path.join(logsDir, 'combined.log');
        const exists = fs.existsSync(combinedLogPath);
        
        expect(exists).toBe(true);
        done();
      }, 100);
    });

    it('should create debug log file in debug mode', (done) => {
      const logger = createLogger({ debugMode: true, silent: true });
      
      logger.debug('Test debug for file');
      
      // Give winston time to write to file
      setTimeout(() => {
        const debugLogPath = path.join(logsDir, 'debug.log');
        const exists = fs.existsSync(debugLogPath);
        
        expect(exists).toBe(true);
        done();
      }, 100);
    });
  });

  describe('error handling', () => {
    it('should not exit on error', () => {
      const logger = createLogger({ silent: true });
      
      expect(logger.exitOnError).toBe(false);
    });

    it('should handle logging errors gracefully', () => {
      const logger = createLogger({ silent: true });
      
      expect(() => {
        logger.error(new Error('Test error object'));
      }).not.toThrow();
    });
  });

  describe('environment variables', () => {
    it('should respect LOG_LEVEL environment variable', () => {
      const originalLogLevel = process.env.LOG_LEVEL;
      process.env.LOG_LEVEL = 'warn';
      
      const logger = createLogger({ silent: true });
      
      expect(logger.level).toBe('warn');
      
      // Restore original value
      if (originalLogLevel) {
        process.env.LOG_LEVEL = originalLogLevel;
      } else {
        delete process.env.LOG_LEVEL;
      }
    });

    it('should respect DEBUG environment variable', () => {
      const originalDebug = process.env.DEBUG;
      process.env.DEBUG = 'true';
      
      const logger = createLogger({ silent: true });
      
      expect(logger.level).toBe('debug');
      
      // Restore original value
      if (originalDebug) {
        process.env.DEBUG = originalDebug;
      } else {
        delete process.env.DEBUG;
      }
    });
  });
});
